div.script:
function toggleImageDisplay(type) {
    var img = document.getElementById('mainProductImage');
    var modelId = document.getElementById('modelIdForImage') ? document.getElementById('modelIdForImage').value : null;
    var btnPic = document.getElementById('btnShowPicture');
    var btnDraw = document.getElementById('btnShowDrawing');
    var msg = document.getElementById('noDrawingMsg');

    if(!img || !modelId) return;

    if(type === 'picture') {
        img.src = '/web/image?model=pdp.product.model&id=' + modelId + '&field=picture_image';
        img.classList.remove('d-none');
        if(msg) msg.classList.add('d-none');

        btnPic.classList.add('btn-secondary');
        btnPic.classList.remove('btn-outline-secondary');
        btnDraw.classList.add('btn-outline-secondary');
        btnDraw.classList.remove('btn-secondary');
    } else {
        // Check if drawing exists via fetch? Or just load it and handle error?
        // Odoo /web/image returns placeholder if empty? 
        // Actually, let's use the field `drawing` on pdp.picture.
        // But pdp.product.model doesn't have `drawing` field yet? 
        // WAIT! I need to add `drawing` computed field to pdp.product.model as well!
        // The plan said "pdp.picture" schema changes. It missed specific "pdp.product.model" compute!
        // For now, let's assume I fix the backend model too.

        img.src = '/web/image?model=pdp.product.model&id=' + modelId + '&field=drawing_image';

        btnDraw.classList.add('btn-secondary');
        btnDraw.classList.remove('btn-outline-secondary');
        btnPic.classList.add('btn-outline-secondary');
        btnPic.classList.remove('btn-secondary');
    }
}

body.script:
// Tabs manual handling
document.querySelectorAll('#pdpTab button').forEach(button => {
    button.addEventListener('click', event => {
        event.preventDefault();
        document.querySelectorAll('#pdpTab button').forEach(b => b.classList.remove('active'));
        document.querySelectorAll('.tab-pane').forEach(p => p.classList.remove('show', 'active'));
        button.classList.add('active');
        const target = document.querySelector(button.getAttribute('data-bs-target'));
        if(target) target.classList.add('show', 'active');
    });
});

// Pricing Interactivity
document.addEventListener('DOMContentLoaded', function() {
    loadPdpOptions();
    const btnSave = document.getElementById('btnSaveOptions');
    if(btnSave) btnSave.addEventListener('click', savePdpOptions);

    // ... existing code ...

    const marginSelect = document.querySelector('select[name="pricing_margin"]');
    const currencySelect = document.querySelector('select[name="pricing_currency"]');
    const updateBtn = document.getElementById('btnUpdatePrice');
    const rateInput = document.getElementById('inputUsRate');
    const productId = document.getElementById('currentProductId').value;

    if(updateBtn && productId) {
       updateBtn.addEventListener('click', function() {
            const marginId = marginSelect ? marginSelect.value : null;
            const currencyId = currencySelect ? currencySelect.value : null;
            const opts = JSON.parse(localStorage.getItem('pdp_options') || '{}');
            const priceSource = opts.priceSource || 'reference';

            // Using Odoo RPC (jsonrpc)
            fetch('/pdp/update_price', {
                    method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    jsonrpc: "2.0",
                    method: "call",
                    params: {
                        product_id: productId,
                        margin_id: marginId,
                        currency_id: currencyId,
                        price_source: priceSource
                    }
                })
            })
            .then(response => response.json())
            .then(data => {
                if(data.result) {
                    if(data.result.error) {
                        alert('Error: ' + data.result.error);
                    } else {
                        renderPriceTable(data.result);
                        if(data.result.currency && rateInput) {
                            rateInput.value = data.result.currency.rate.toFixed(4);
                        }
                    }
                } else if (data.error) {
                    console.error(data.error);
                    alert("Server Error");
                }
            });
       });
    }

    // Helper to render table
    function renderPriceTable(data) {
        const tbody = document.querySelector('#priceTableBody');
        if(!tbody) return;
        tbody.innerHTML = '';

        const fmt = (val) => {
             // Simple formatter, ideally use Intl.NumberFormat based on currency info
             return val.toFixed(2) + ' ' + (data.currency.symbol || '');
        };

        data.lines.forEach(line => {
            const row = `

                ${line.type}
                ${fmt(line.cost)}
                ${fmt(line.margin)}
                ${fmt(line.price)}
            `;
            tbody.innerHTML += row;
        });

        // Totals
        const total = `


                Net / Final
                ${fmt(data.totals.cost)}
                ${fmt(data.totals.margin)}
                ${fmt(data.totals.price)}

        `;
        tbody.innerHTML += total;
    }
    }
});

// Options Logic
function loadPdpOptions() {
    const opts = JSON.parse(localStorage.getItem('pdp_options') || '{}');

    // Set Inputs
    if(document.getElementById('optShowCost')) document.getElementById('optShowCost').checked = opts.showCost !== false;
    if(document.getElementById('optAutoRefresh')) document.getElementById('optAutoRefresh').checked = !!opts.autoRefresh;
    if(document.getElementById('optRefreshInterval')) document.getElementById('optRefreshInterval').value = opts.refreshInterval || 30;
    if(document.getElementById('optWeightUnit')) document.getElementById('optWeightUnit').value = opts.weightUnit || 'g';
    if(document.getElementById('optPriceSource')) document.getElementById('optPriceSource').value = opts.priceSource || 'reference';

    // Apply Settings
    applyPdpSettings(opts);
}

function savePdpOptions() {
    try {
        console.log('Saving PDP Options...');
        const opts = {
            showCost: document.getElementById('optShowCost').checked,
            autoRefresh: document.getElementById('optAutoRefresh').checked,
            refreshInterval: parseInt(document.getElementById('optRefreshInterval').value) || 30,
            weightUnit: document.getElementById('optWeightUnit').value,
            priceSource: document.getElementById('optPriceSource').value
        };
        localStorage.setItem('pdp_options', JSON.stringify(opts));

        applyPdpSettings(opts);

        // Close modal (bootstrap5)
        const modalEl = document.getElementById('optionsModal');
        const modal = bootstrap.Modal.getOrCreateInstance(modalEl);
        if(modal) modal.hide();
        else console.warn('Modal instance not found');
    } catch(e) {
        console.error(e);
        alert('Error saving options: ' + e.message);
    }
}

let refreshTimer = null;

function applyPdpSettings(opts) {
    // Auto Refresh
    if(refreshTimer) clearInterval(refreshTimer);
    if(opts.autoRefresh) {
        refreshTimer = setInterval(() => {
            window.location.reload();
        }, opts.refreshInterval * 1000);
    }

    // Weight Unit
    updateWeightDisplay(opts.weightUnit);

    // Cost Visibility
    updateCostVisibility(opts.showCost !== false);
}

function updateWeightDisplay(unit) {
    unit = unit || 'g';
    const factors = { 'g': 1, 'oz': 0.035274, 'ct': 5 };
    const factor = factors[unit] || 1;
    const precision = unit === 'ct' ? 2 : (unit === 'oz' ? 4 : 2);

    document.querySelectorAll('.pdp-weight').forEach(el => {
        const val = parseFloat(el.getAttribute('data-weight')) || 0;
        const conv = val * factor;
        el.innerText = conv.toFixed(precision);
    });
}

function updateCostVisibility(show) {
    const styleId = 'pdp-cost-style';
    let style = document.getElementById(styleId);
    if (!style) {
        style = document.createElement('style');
        style.id = styleId;
        document.head.appendChild(style);
    }
    if (show) {
        style.textContent = '';
    } else {
        style.textContent = '.pdp-cost { display: none !important; }';
    }
}
